#!/usr/bin/env python3
"""
Bug #2598: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'reshape_layernorm_reshape'], ['constant', 'transpose_identity_perm'], ['normalization', 'layernorm_axis1'], ['layout', 'resize_cubic_halfpixel'], ['normalization', 'layernorm_temperature'], ['normalization', 'layernorm_dropout_identity']]
Dependencies: numpy jax
Run         : python unique_2598.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("ffffffffffffffff000c000000000000"), dtype=np.int64).reshape([2])
_w1 = np.frombuffer(bytes.fromhex("ffffffffffffffff030000000000000020000000000000002000000000000000"), dtype=np.int64).reshape([4])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([3072])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([3072])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([3, 32, 32])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([3, 32, 32])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w7 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w10 = np.frombuffer(bytes.fromhex("00001040"), dtype=np.float32).reshape([1])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 64, 64])
_w12 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w13 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w14 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_rlnr_r2d = jnp.reshape(x, [int(v) for v in _w0.flat])
    n0_rlnr_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n0_rlnr_r2d)) * _w2) + _w3
    n0_rlnr_out = jnp.reshape(n0_rlnr_ln, [int(v) for v in _w1.flat])
    n100_tip_tp = jnp.transpose(n0_rlnr_out, [0, 1, 2, 3])
    n100_tip_out = n100_tip_tp * n0_rlnr_out
    n200_la1_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(1%_x.ndim, _x.ndim)), keepdims=True)))(n100_tip_out)) * _w4) + _w5
    n300_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(n200_la1_out, _w7)
    n400_lnt_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n300_resi_out)) * _w8) + _w9
    n400_lnt_div = n400_lnt_ln / _w10
    n400_lnt_out = n400_lnt_div + _w11
    n500_lnd_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n400_lnt_out)) * _w12) + _w13
    n500_lnd_out = n500_lnd_ln
    return jnp.asarray(n500_lnd_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
